def f(expr):
    s = expr.replace(' ', '')
    precedence = {'+': 1, '-': 1, '*': 2}
    values = []
    ops = []

    def apply_op():
        b = values.pop()
        a = values.pop()
        op = ops.pop()
        if op == '+':
            values.append(a + b)
        elif op == '-':
            values.append(a - b)
        else:  # '*'
            values.append(a * b)

    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if ch.isdigit():
            num = 0
            while i < n and s[i].isdigit():
                num = num * 10 + int(s[i])
                i += 1
            values.append(num)
            continue
        if ch == '(':
            ops.append(ch)
        elif ch == ')':
            while ops and ops[-1] != '(':
                apply_op()
            ops.pop()  # remove '('
        else:  # operator + - *
            while ops and ops[-1] != '(' and precedence[ops[-1]] >= precedence[ch]:
                apply_op()
            ops.append(ch)
        i += 1

    while ops:
        apply_op()
    return values[-1] if values else 0
